const fs = require('fs');
const readline = require('readline');
const path = require('path');

const logsDir = 'C:\\Users\\HP\\.gemini\\antigravity\\brain\\dc2c2d34-c0b3-444e-8541-9a8565f19676\\.system_generated\\logs';
const transcriptFullPath = path.join(logsDir, 'transcript_full.jsonl');

async function run() {
  if (!fs.existsSync(transcriptFullPath)) {
    console.log('No transcript_full.jsonl found');
    return;
  }

  const fileStream = fs.createReadStream(transcriptFullPath);
  const rl = readline.createInterface({
    input: fileStream,
    crlfDelay: Infinity
  });

  let matchCount = 0;
  for await (const line of rl) {
    if (line.includes('fileEditorTab') && line.includes('className') && line.includes('div')) {
      matchCount++;
      console.log(`Match ${matchCount}: contains fileEditorTab with JSX keywords`);
      // Print the JSON string or parts of it
      try {
        const obj = JSON.parse(line);
        console.log(`  Step ${obj.step_index} (${obj.type})`);
        // If it's a replacement or content, save it to a temp file to inspect
        const tempPath = path.join(__dirname, '..', `scratch/found_editor_step_${obj.step_index}.json`);
        fs.writeFileSync(tempPath, JSON.stringify(obj, null, 2), 'utf8');
        console.log(`  Saved to ${tempPath}`);
      } catch (e) {
        console.log('  Failed to parse line JSON');
      }
    }
  }
  console.log('Done scanning.');
}

run();
